function preorder(node):
    if node == null:
        return

    visit(node)
    preorder(node.left)
    preorder(node.right)

function inorder(node):
    if node == null:
        return

    inorder(node.left)
    visit(node)
    inorder(node.right)

function postorder(node):
    if node == null:
        return

    postorder(node.left)
    postorder(node.right)
    visit(node)

function hasPathSum(node, target, currentSum):
    if node == null:
        return false

    currentSum += node.value

    if node.left == null and node.right == null:
        return currentSum == target

    return hasPathSum(node.left, target, currentSum) OR
           hasPathSum(node.right, target, currentSum)
